// ===== CURSOR SYSTEM =====
const cursorOrb = document.getElementById('cursor-orb');
const cursorFollower = document.getElementById('cursor-follower');
const trailContainer = document.getElementById('cursor-trail-container');
const burstContainer = document.getElementById('particle-burst-container');

let mouseX = window.innerWidth/2, mouseY = window.innerHeight/2;
let followerX = mouseX, followerY = mouseY;
let trailPoints = [];
const TRAIL_COUNT = 12;

document.addEventListener('mousemove', (e) => {
  mouseX = e.clientX; mouseY = e.clientY;
  cursorOrb.style.left = mouseX + 'px';
  cursorOrb.style.top  = mouseY + 'px';
  createTrail(mouseX, mouseY);
});

function animateFollower() {
  followerX += (mouseX - followerX) * 0.12;
  followerY += (mouseY - followerY) * 0.12;
  cursorFollower.style.left = followerX + 'px';
  cursorFollower.style.top  = followerY + 'px';
  requestAnimationFrame(animateFollower);
}
animateFollower();

function createTrail(x, y) {
  const dot = document.createElement('div');
  dot.className = 'cursor-trail';
  dot.style.left = x + 'px';
  dot.style.top  = y + 'px';
  dot.style.opacity = '0.6';
  dot.style.transform = 'translate(-50%,-50%) scale(1)';
  trailContainer.appendChild(dot);
  setTimeout(() => dot.remove(), 500);
}

function createBurst(x, y) {
  for(let i = 0; i < 8; i++){
    const p = document.createElement('div');
    p.style.cssText = `
      position:fixed; width:5px; height:5px;
      background:var(--cyan); border-radius:50%;
      pointer-events:none; z-index:99996;
      left:${x}px; top:${y}px;
      transform:translate(-50%,-50%);
      box-shadow: 0 0 6px var(--cyan);
    `;
    burstContainer.appendChild(p);
    const angle = (i / 8) * Math.PI * 2;
    const dist = 30 + Math.random() * 40;
    const tx = Math.cos(angle) * dist;
    const ty = Math.sin(angle) * dist;
    p.animate([
      { transform: 'translate(-50%,-50%) scale(1)', opacity: 1 },
      { transform: `translate(calc(-50% + ${tx}px), calc(-50% + ${ty}px)) scale(0)`, opacity: 0 }
    ], { duration: 500, easing: 'ease-out', fill: 'forwards' }).onfinish = () => p.remove();
  }
}

document.addEventListener('click', (e) => {
  createBurst(e.clientX, e.clientY);
});

