// ===== ANIMATED BACKGROUND PARTICLES =====
(function(){
  const canvas = document.getElementById('bg-canvas');
  const ctx = canvas.getContext('2d');
  let W, H, particles = [];

  function resize(){
    W = canvas.width  = window.innerWidth;
    H = canvas.height = window.innerHeight;
  }
  resize();
  window.addEventListener('resize', resize);

  class Particle {
    constructor(){
      this.x = Math.random() * W;
      this.y = Math.random() * H;
      this.vx = (Math.random()-.5)*.4;
      this.vy = (Math.random()-.5)*.4 - .3;
      this.size = Math.random()*2 + .5;
      this.alpha = Math.random()*.7 + .1;
      this.hue = Math.random() > .7 ? 200 : 185;
      this.life = 0;
      this.maxLife = Math.random()*300+150;
    }
    update(){
      this.x += this.vx; this.y += this.vy; this.life++;
      if(this.life > this.maxLife || this.x<0 || this.x>W || this.y<0 || this.y>H) {
        this.x = Math.random()*W; this.y = H + 10;
        this.life = 0; this.maxLife = Math.random()*300+150;
      }
    }
    draw(){
      const progress = this.life / this.maxLife;
      const a = this.alpha * (progress < 0.1 ? progress*10 : progress > 0.9 ? (1-progress)*10 : 1);
      ctx.save();
      ctx.globalAlpha = a;
      ctx.shadowBlur = 8;
      ctx.shadowColor = `hsla(${this.hue},100%,70%,0.8)`;
      ctx.fillStyle = `hsla(${this.hue},100%,75%,1)`;
      ctx.beginPath();
      ctx.arc(this.x, this.y, this.size, 0, Math.PI*2);
      ctx.fill();
      ctx.restore();
    }
  }

  for(let i=0;i<120;i++) particles.push(new Particle());

  function animate(){
    ctx.clearRect(0,0,W,H);
    // Draw subtle connections
    for(let i=0;i<particles.length;i++){
      for(let j=i+1;j<particles.length;j++){
        const dx = particles[i].x - particles[j].x;
        const dy = particles[i].y - particles[j].y;
        const dist = Math.sqrt(dx*dx+dy*dy);
        if(dist < 100){
          ctx.save();
          ctx.globalAlpha = (1-dist/100)*0.06;
          ctx.strokeStyle = '#00f5ff';
          ctx.lineWidth = .5;
          ctx.beginPath();
          ctx.moveTo(particles[i].x, particles[i].y);
          ctx.lineTo(particles[j].x, particles[j].y);
          ctx.stroke();
          ctx.restore();
        }
      }
    }
    particles.forEach(p=>{ p.update(); p.draw(); });
    requestAnimationFrame(animate);
  }
  animate();
})();

// ===== CALCULATOR ENGINE =====
let display = '', preview = '', operator = '', firstNum = '', secondNum = '';
let isNewEntry = true, memoryVal = 0, mode = 'basic', justCalculated = false;
let currentVal = '0';

function getDisplay(){ return document.getElementById('calc-main'); }
function getPreview(){ return document.getElementById('calc-preview'); }

function updateDisplay(val, pv){
  const d = getDisplay();
  const prev = d.textContent;
  d.textContent = val || '0';
  d.classList.remove('pulse-anim');
  void d.offsetWidth;
  if(prev !== val) d.classList.add('pulse-anim');
  if(pv !== undefined) getPreview().textContent = pv;
}

function inputNum(n){
  animateBtn(event?.target);
  if(justCalculated){ currentVal = ''; justCalculated = false; }
  if(currentVal === '0' && n !== '.') currentVal = n;
  else if(currentVal.length < 16) currentVal += n;
  updateDisplay(currentVal, operator ? firstNum + ' ' + operator : '');
}

function inputDecimal(){
  animateBtn(event?.target);
  if(justCalculated){ currentVal = '0'; justCalculated = false; }
  if(!currentVal.includes('.')) currentVal += '.';
  updateDisplay(currentVal);
}

function setOperator(op){
  animateBtn(event?.target);
  if(firstNum && !isNewEntry && currentVal){
    const result = compute(parseFloat(firstNum), parseFloat(currentVal), operator);
    if(result === 'ERROR'){ showError(); return; }
    firstNum = String(result);
    currentVal = '';
    updateDisplay(formatNum(parseFloat(firstNum)), firstNum + ' ' + op);
  } else {
    firstNum = currentVal || firstNum || '0';
    currentVal = '';
    updateDisplay(formatNum(parseFloat(firstNum)), firstNum + ' ' + op);
  }
  operator = op;
  isNewEntry = false;
  justCalculated = false;
}

function calculate(){
  animateBtn(event?.target);
  if(!operator || firstNum === '') return;
  const a = parseFloat(firstNum);
  const b = parseFloat(currentVal || firstNum);
  const result = compute(a, b, operator);
  if(result === 'ERROR'){ showError(); return; }
  const formatted = formatNum(result);
  updateDisplay(formatted, firstNum + ' ' + operator + ' ' + (currentVal || firstNum) + ' =');
  currentVal = String(result);
  firstNum = ''; operator = '';
  isNewEntry = true; justCalculated = true;
  burstDisplay();
}

function compute(a, b, op){
  switch(op){
    case '+': return a + b;
    case '-': return a - b;
    case '×': return a * b;
    case '÷': return b === 0 ? 'ERROR' : a / b;
    default:  return b;
  }
}

function formatNum(n){
  if(isNaN(n) || !isFinite(n)) return 'ERROR';
  if(Number.isInteger(n) && Math.abs(n) < 1e12) return String(n);
  if(Math.abs(n) >= 1e12 || (Math.abs(n) < 0.0001 && n !== 0)) return n.toExponential(4);
  const str = n.toPrecision(10);
  return parseFloat(str).toString();
}

function clearAll(){
  animateBtn(event?.target);
  currentVal = '0'; firstNum = ''; operator = ''; isNewEntry = true; justCalculated = false;
  updateDisplay('0', '');
}

function deleteLast(){
  animateBtn(event?.target);
  if(justCalculated){ clearAll(); return; }
  if(currentVal.length > 1) currentVal = currentVal.slice(0,-1);
  else currentVal = '0';
  updateDisplay(currentVal);
}

function toggleSign(){
  animateBtn(event?.target);
  if(!currentVal || currentVal === '0') return;
  currentVal = currentVal.startsWith('-') ? currentVal.slice(1) : '-'+currentVal;
  updateDisplay(currentVal);
}

function percentage(){
  animateBtn(event?.target);
  const v = parseFloat(currentVal || '0');
  currentVal = String(v / 100);
  updateDisplay(formatNum(v/100));
}

function sciFunc(fn){
  animateBtn(event?.target);
  const v = parseFloat(currentVal || '0');
  let result;
  switch(fn){
    case 'sin':  result = Math.sin(v * Math.PI/180); break;
    case 'cos':  result = Math.cos(v * Math.PI/180); break;
    case 'tan':  result = Math.tan(v * Math.PI/180); break;
    case 'log':  result = v <= 0 ? 'ERROR' : Math.log10(v); break;
    case 'ln':   result = v <= 0 ? 'ERROR' : Math.log(v); break;
    case 'sqrt': result = v < 0  ? 'ERROR' : Math.sqrt(v); break;
    case 'pow2': result = Math.pow(v,2); break;
    case 'pow3': result = Math.pow(v,3); break;
    case 'inv':  result = v === 0 ? 'ERROR' : 1/v; break;
    case 'pi':   result = Math.PI; currentVal = String(Math.PI); updateDisplay(formatNum(Math.PI)); return;
    case 'e':    result = Math.E; currentVal = String(Math.E); updateDisplay(formatNum(Math.E)); return;
    case 'abs':  result = Math.abs(v); break;
    default: return;
  }
  if(result === 'ERROR'){ showError(); return; }
  const fr = formatNum(result);
  getPreview().textContent = fn+'(' + v + ') =';
  currentVal = String(result);
  updateDisplay(fr);
  justCalculated = true;
}

function memStore(){
  memoryVal = parseFloat(currentVal || '0');
  document.getElementById('memVal').textContent = formatNum(memoryVal);
  pulseElement(document.querySelector('.mem-display'));
}
function memClear(){
  memoryVal = 0;
  document.getElementById('memVal').textContent = '0';
}
function memRecall(){
  currentVal = String(memoryVal);
  updateDisplay(formatNum(memoryVal));
}
function memAdd(){
  memoryVal += parseFloat(currentVal || '0');
  document.getElementById('memVal').textContent = formatNum(memoryVal);
}
function memSub(){
  memoryVal -= parseFloat(currentVal || '0');
  document.getElementById('memVal').textContent = formatNum(memoryVal);
}

function setMode(m){
  mode = m;
  document.getElementById('basicButtons').classList.toggle('hidden', m !== 'basic');
  document.getElementById('sciButtons').classList.toggle('hidden', m !== 'sci');
  document.getElementById('basicMode').classList.toggle('active', m === 'basic');
  document.getElementById('sciMode').classList.toggle('active', m === 'sci');
}

// ===== VISUAL HELPERS =====
function animateBtn(btn){
  if(!btn || !btn.classList) return;
  btn.classList.remove('btn-pressed');
  void btn.offsetWidth;
  btn.classList.add('btn-pressed');
  setTimeout(()=> btn.classList.remove('btn-pressed'), 150);
}

function burstDisplay(){
  const d = getDisplay();
  d.style.boxShadow = '0 0 40px rgba(0,245,255,0.6), 0 0 80px rgba(0,245,255,0.3)';
  setTimeout(()=> d.style.boxShadow = '', 300);
}

function showError(){
  const d = getDisplay();
  d.textContent = 'ERROR';
  d.style.color = '#ff5555';
  d.classList.add('shake-anim');
  setTimeout(()=>{
    d.style.color = '';
    d.classList.remove('shake-anim');
    clearAll();
  }, 1000);
}

function pulseElement(el){
  if(!el) return;
  el.style.color = 'var(--cyan)';
  el.style.textShadow = 'var(--glow-cyan)';
  setTimeout(()=>{ el.style.color=''; el.style.textShadow=''; }, 500);
}

// ===== KEYBOARD SUPPORT =====
document.addEventListener('keydown', (e) => {
  if(e.key >= '0' && e.key <= '9') inputNum(e.key);
  else if(e.key === '.') inputDecimal();
  else if(e.key === '+') setOperator('+');
  else if(e.key === '-') setOperator('-');
  else if(e.key === '*') setOperator('×');
  else if(e.key === '/') { e.preventDefault(); setOperator('÷'); }
  else if(e.key === 'Enter' || e.key === '=') calculate();
  else if(e.key === 'Backspace') deleteLast();
  else if(e.key === 'Escape') clearAll();
  else if(e.key === '%') percentage();
});

// ===== IDLE SCANNER on calc display =====
let idleTimer;
function resetIdle(){
  clearTimeout(idleTimer);
  const scan = document.querySelector('.display-scanline');
  if(scan) scan.style.animationDuration = '4s';
  idleTimer = setTimeout(()=>{
    const scan = document.querySelector('.display-scanline');
    if(scan) scan.style.animationDuration = '1.5s';
  }, 5000);
}
document.addEventListener('click', resetIdle);
document.addEventListener('keydown', resetIdle);

